def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
        else:
            score = 0
            for j in range(1, 6):
                weight = 1 / j
                try:
                    score += weight * np.log(1 / (ratio + 0.01 * j))
                except:
                    score += 0
            if capacity < item * 1.5:
                score *= 1.5
            elif capacity > item * 3:
                score *= 0.5
            priorities[i] = -score
    max_priority = np.max(priorities[np.isfinite(priorities)]) if np.any(np.isfinite(priorities)) else 1
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 1.1
    return priorities
